# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount
        return self.balance

    def withdraw(self, amount):
        if amount > self.balance:
            print("Insufficient funds")
            return None
        else:
            self.balance -= amount
            return self.balance

class TransactionProcessor:
    def __init__(self):
        self.account = Account()

    def process_transaction(self, transaction):
        account, amount = transaction
        account.deposit(amount)
        print(f"Transaction processed for {account}: New balance is {account.balance}")

processor = TransactionProcessor()
transactions = [("Savings", 1000), ("Checking", 500)]
for transaction in transactions:
    processor.process_transaction(transaction)